import axios from 'axios'
import type { Task, Project, User, TaskFilter, PaginatedResponse, ApiResponse } from '@/types'

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:8000/api'

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
})

// Add request interceptor for auth token
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('auth_token')
  if (token) {
    config.headers.Authorization = `Bearer ${token}`
  }
  return config
})

// Tasks API
export const tasksApi = {
  getAll: async (filters?: TaskFilter): Promise<PaginatedResponse<Task>> => {
    const params = new URLSearchParams()
    if (filters?.status) filters.status.forEach(s => params.append('status', s))
    if (filters?.priority) filters.priority.forEach(p => params.append('priority', p))
    if (filters?.projectId) params.append('project', filters.projectId)
    if (filters?.assigneeId) params.append('assignee', filters.assigneeId)
    if (filters?.search) params.append('search', filters.search)

    const { data } = await api.get<PaginatedResponse<Task>>(`/tasks/?${params.toString()}`)
    return data
  },

  getById: async (id: string): Promise<Task> => {
    const { data } = await api.get<ApiResponse<Task>>(`/tasks/${id}/`)
    return data.data
  },

  create: async (task: Partial<Task>): Promise<Task> => {
    const { data } = await api.post<ApiResponse<Task>>('/tasks/', task)
    return data.data
  },

  update: async (id: string, task: Partial<Task>): Promise<Task> => {
    const { data } = await api.patch<ApiResponse<Task>>(`/tasks/${id}/`, task)
    return data.data
  },

  delete: async (id: string): Promise<void> => {
    await api.delete(`/tasks/${id}/`)
  },

  updateStatus: async (id: string, status: Task['status']): Promise<Task> => {
    return tasksApi.update(id, { status })
  },
}

// Projects API
export const projectsApi = {
  getAll: async (): Promise<Project[]> => {
    const { data } = await api.get<ApiResponse<Project[]>>('/projects/')
    return data.data
  },

  getById: async (id: string): Promise<Project> => {
    const { data } = await api.get<ApiResponse<Project>>(`/projects/${id}/`)
    return data.data
  },

  create: async (project: Partial<Project>): Promise<Project> => {
    const { data } = await api.post<ApiResponse<Project>>('/projects/', project)
    return data.data
  },

  update: async (id: string, project: Partial<Project>): Promise<Project> => {
    const { data } = await api.patch<ApiResponse<Project>>(`/projects/${id}/`, project)
    return data.data
  },

  delete: async (id: string): Promise<void> => {
    await api.delete(`/projects/${id}/`)
  },
}

// Users API
export const usersApi = {
  getCurrentUser: async (): Promise<User> => {
    const { data } = await api.get<ApiResponse<User>>('/users/me/')
    return data.data
  },

  getAll: async (): Promise<User[]> => {
    const { data } = await api.get<ApiResponse<User[]>>('/users/')
    return data.data
  },
}

