import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from 'react-query'
import { tasksApi, projectsApi } from '@/lib/api'
import TaskCard from '@/components/TaskCard'
import TaskFilter from '@/components/TaskFilter'
import TaskForm from '@/components/TaskForm'
import type { Task, TaskFilter as TaskFilterType, Project } from '@/types'
import { PlusIcon } from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'

export default function TasksPage() {
  const [filters, setFilters] = useState<TaskFilterType>({})
  const [showForm, setShowForm] = useState(false)
  const queryClient = useQueryClient()

  const { data: tasksData, isLoading } = useQuery(
    ['tasks', filters],
    () => tasksApi.getAll(filters)
  )

  const { data: projects } = useQuery<Project[]>('projects', projectsApi.getAll)

  const createMutation = useMutation(tasksApi.create, {
    onSuccess: () => {
      queryClient.invalidateQueries('tasks')
      toast.success('Task created successfully')
      setShowForm(false)
    },
    onError: () => {
      toast.error('Failed to create task')
    },
  })

  const handleCreateTask = async (task: Partial<Task>) => {
    await createMutation.mutateAsync(task)
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-900">Tasks</h1>
        <button
          onClick={() => setShowForm(!showForm)}
          className="btn-primary flex items-center"
        >
          <PlusIcon className="w-5 h-5 mr-2" />
          New Task
        </button>
      </div>

      {showForm && (
        <div className="card mb-6">
          <h2 className="text-xl font-semibold mb-4">Create New Task</h2>
          <TaskForm
            onSubmit={handleCreateTask}
            onCancel={() => setShowForm(false)}
          />
        </div>
      )}

      {projects && (
        <TaskFilter
          filters={filters}
          onChange={setFilters}
          projects={projects}
        />
      )}

      {isLoading ? (
        <div className="text-center py-12">Loading tasks...</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {tasksData?.results.map((task) => (
            <TaskCard key={task.id} task={task} />
          ))}
          {tasksData?.results.length === 0 && (
            <p className="text-gray-500 col-span-full text-center py-12">
              No tasks found. Create your first task!
            </p>
          )}
        </div>
      )}
    </div>
  )
}

