import { useParams, useNavigate } from 'react-router-dom'
import { useQuery, useMutation, useQueryClient } from 'react-query'
import { tasksApi } from '@/lib/api'
import TaskForm from '@/components/TaskForm'
import type { Task } from '@/types'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import { ArrowLeftIcon, TrashIcon } from '@heroicons/react/24/outline'

export default function TaskDetail() {
  const { id } = useParams<{ id: string }>()
  const navigate = useNavigate()
  const queryClient = useQueryClient()

  const { data: task, isLoading } = useQuery<Task>(
    ['task', id],
    () => tasksApi.getById(id!),
    { enabled: !!id }
  )

  const updateMutation = useMutation(
    (data: Partial<Task>) => tasksApi.update(id!, data),
    {
      onSuccess: () => {
        queryClient.invalidateQueries(['task', id])
        queryClient.invalidateQueries('tasks')
        toast.success('Task updated successfully')
      },
      onError: () => {
        toast.error('Failed to update task')
      },
    }
  )

  const deleteMutation = useMutation(() => tasksApi.delete(id!), {
    onSuccess: () => {
      queryClient.invalidateQueries('tasks')
      toast.success('Task deleted successfully')
      navigate('/tasks')
    },
    onError: () => {
      toast.error('Failed to delete task')
    },
  })

  if (isLoading) {
    return <div className="text-center py-12">Loading task...</div>
  }

  if (!task) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500 mb-4">Task not found</p>
        <button onClick={() => navigate('/tasks')} className="btn-primary">
          Back to Tasks
        </button>
      </div>
    )
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <button
          onClick={() => navigate('/tasks')}
          className="flex items-center text-gray-600 hover:text-gray-900"
        >
          <ArrowLeftIcon className="w-5 h-5 mr-2" />
          Back to Tasks
        </button>
        <button
          onClick={() => deleteMutation.mutate()}
          className="flex items-center text-red-600 hover:text-red-700"
        >
          <TrashIcon className="w-5 h-5 mr-2" />
          Delete
        </button>
      </div>

      <div className="card">
        <h1 className="text-3xl font-bold text-gray-900 mb-6">{task.title}</h1>

        <TaskForm
          task={task}
          onSubmit={async (data) => await updateMutation.mutateAsync(data)}
          onCancel={() => navigate('/tasks')}
        />
      </div>
    </div>
  )
}

