              )}

              <div className="text-sm text-gray-500">
                <p>Created: {format(new Date(project.createdAt), 'MMM d, yyyy')}</p>
                {project.taskCount !== undefined && (
                  <p>Tasks: {project.taskCount}</p>
                )}
              </div>
            </div>
          ))}

          {projects?.length === 0 && (
            <p className="text-gray-500 col-span-full text-center py-12">
              No projects yet. Create your first project!
            </p>
          )}
        </div>
      )}

      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-6 max-w-md w-full">
            <h2 className="text-xl font-semibold mb-4">
              {editingProject ? 'Edit Project' : 'Create Project'}
            </h2>
            <ProjectForm
              project={editingProject}
              onSubmit={handleSubmit}
              onCancel={() => {
                setShowForm(false)
                setEditingProject(null)
              }}
            />
          </div>
        </div>
      )}
    </div>
  )
}

function ProjectForm({ project, onSubmit, onCancel }: { project: Project | null, onSubmit: (p: Partial<Project>) => Promise<void>, onCancel: () => void }) {
  const [formData, setFormData] = useState<Partial<Project>>({
    name: project?.name || '',
    description: project?.description || '',
    color: project?.color || '#3B82F6',
  })

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    await onSubmit(formData)
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Name *
        </label>
        <input
          type="text"
          required
          className="input-field"
          value={formData.name || ''}
          onChange={(e) => setFormData({ ...formData, name: e.target.value })}
        />
      </div>

      <div>
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Description
        </label>
        <textarea
          rows={3}
          className="input-field"
          value={formData.description || ''}
          onChange={(e) => setFormData({ ...formData, description: e.target.value })}
        />
      </div>

      <div>
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Color
        </label>
        <input
          type="color"
          className="w-full h-10 rounded"
          value={formData.color}
          onChange={(e) => setFormData({ ...formData, color: e.target.value })}
        />
      </div>

      <div className="flex justify-end space-x-3 pt-4">
        <button type="button" onClick={onCancel} className="btn-secondary">
          Cancel
        </button>
        <button type="submit" className="btn-primary">
          {project ? 'Update' : 'Create'} Project
        </button>
      </div>
    </form>
  )
}
